bool isSameTree(TreeNode* p, TreeNode* q) {
        if(!p&&!q)return true;//都为空
        if(!p||!q)return false;//至少一方为空
        if(p->val==q->val)//如果跟节点相等
            return isSameTree(p->left,q->left)&&isSameTree(p->right,q->right);//判断左右子树是否相等
