class Solution {
public:
    bool isPalindrome(string s) {
      if (s.size() <= 1)return true;
	 transform(s.begin(), s.end(), s.begin(), ::tolower);
	 cout << s << endl;
	 int l = 0, r = s.size() - 1;

	 while (l < r)
	 {
		 while (l<s.size()&&s[l]<'a' || s[l]>'z')l++;
		 while (r<s.size()&&s[r]<'a' || s[r]>'z')r--;
		 cout << s[l] << "-" << s[r] << endl;
