最近在使用OpenCV中adaboost训练分类器，由于缺少部分负样本，一开始打算写一个randomcrop函数来随机截取获得负样本，这样效率比较高，但是这样截取的样本比较随机，负样本比较复杂，没有针对性，对于小型分类器会导致分类效果不过，然而对于特定场景，负样本往往比较单一类型，所以自己手动截取或许更有针对性。在OpenCV中有相关的用户交互接口，最直观的就是鼠标键盘操作。下面就随便写了一个基于OpenCV使用鼠标操作来截图并保存。
<!-- more -->


具体代码如下：
```
#include <opencv2/opencv.hpp>  
#include <iostream>
#include <string>  
#include<io.h>
using namespace cv;
using namespace std;

string sourcefolder = "C:\\Users\\niceliu\\Desktop\\baby";//图片集文件夹
string savefolder = "C:\\Users\\niceliu\\Desktop\\baby\\crop";//截取保存的文件夹
cv::Size savesize = cv::Size(140, 140);
cv::Mat org, dst, img, tmp;
static int cnt = 0;
void getFiles(string path, vector<string>& files);
void on_mouse(int event, int x, int y, int flags, void *ustc);
int main()
{
	string tmpstr = "mkdir " + savefolder;
	system(tmpstr.c_str());

	vector<string> files;
	getFiles(sourcefolder, files);
	for (size_t i = 0; i < files.size(); i++)
	{
		org = imread(files[i]);
		org.copyTo(img);
		org.copyTo(tmp);
		namedWindow("img");//定义一个img窗口  
		setMouseCallback("img", on_mouse, 0);//调用回调函数  
		imshow("img", img);
		char ckey = waitKey(0);
		if (ckey == 27)return 0;
		if (ckey == 13 || ckey == 32)//space或Enter键，下一张
			continue;
	}
}
void getFiles(string path, vector<string>& files)//遍历图片文件
{
	long   hFile = 0;
	struct _finddata_t fileinfo;
	string p;
	if ((hFile = _findfirst(p.assign(path).append("\\*").c_str(), &fileinfo)) != -1)
	{
		do
		{
			if ((fileinfo.attrib &  _A_SUBDIR))
			{
				if (strcmp(fileinfo.name, ".") != 0 && strcmp(fileinfo.name, "..") != 0)
					getFiles(p.assign(path).append("\\").append(fileinfo.name), files);
			}
			else
			{
				files.push_back(p.assign(path).append("\\").append(fileinfo.name));
			}
		} while (_findnext(hFile, &fileinfo) == 0);

		_findclose(hFile);
	}
}
void on_mouse(int event, int x, int y, int flags, void *ustc)//event鼠标事件代号，x,y鼠标坐标，flags拖拽和键盘操作的代号  
{
	static Point pre_pt = (-1, -1);//初始坐标  
	static Point cur_pt = (-1, -1);//实时坐标  
	std::ostringstream ss;
	if (event == CV_EVENT_LBUTTONDOWN)//左键按下，读取初始坐标，并在图像上该点处划圆  
	{
		org.copyTo(img);//将原始图片复制到img中  
		ss << x << "," << y;
		pre_pt = Point(x, y);
		putText(img, ss.str(), pre_pt, FONT_HERSHEY_SIMPLEX, 0.5, Scalar(0, 0, 0, 255), 1, 8);//在窗口上显示坐标  
		circle(img, pre_pt, 2, Scalar(255, 0, 0, 0), CV_FILLED, CV_AA, 0);//划圆  
		imshow("img", img);
	}
	else if (event == CV_EVENT_MOUSEMOVE && !(flags & CV_EVENT_FLAG_LBUTTON))//左键没有按下的情况下鼠标移动的处理函数  
	{
		img.copyTo(tmp);//将img复制到临时图像tmp上，用于显示实时坐标  
		ss << x << "," << y;
		cur_pt = Point(x, y);
		putText(tmp, ss.str(), cur_pt, FONT_HERSHEY_SIMPLEX, 0.5, Scalar(0, 0, 0, 255));//只是实时显示鼠标移动的坐标  
		imshow("img", tmp);
	}
	else if (event == CV_EVENT_MOUSEMOVE && (flags & CV_EVENT_FLAG_LBUTTON))//左键按下时，鼠标移动，则在图像上划矩形  
	{
		img.copyTo(tmp);
		ss << x << "," << y;
		cur_pt = Point(x, y);
		putText(tmp, ss.str(), cur_pt, FONT_HERSHEY_SIMPLEX, 0.5, Scalar(0, 0, 0, 255));
		rectangle(tmp, pre_pt, cur_pt, Scalar(0, 255, 0, 0), 1, 8, 0);//在临时图像上实时显示鼠标拖动时形成的矩形  
		imshow("img", tmp);
	}
	else if (event == CV_EVENT_LBUTTONUP)//左键松开，将在图像上划矩形  
	{
		org.copyTo(img);
		ss << x << "," << y;
		cur_pt = Point(x, y);
		putText(img, ss.str(), cur_pt, FONT_HERSHEY_SIMPLEX, 0.5, Scalar(0, 0, 0, 255));
		circle(img, pre_pt, 2, Scalar(255, 0, 0, 0), CV_FILLED, CV_AA, 0);
		rectangle(img, pre_pt, cur_pt, Scalar(0, 255, 0, 0), 1, 8, 0);//根据初始点和结束点，将矩形画到img上  
		imshow("img", img);
		img.copyTo(tmp);
		//截取矩形包围的图像，并保存到dst中  
		int width = abs(pre_pt.x - cur_pt.x);
		int height = abs(pre_pt.y - cur_pt.y);
		if (width == 0 || height == 0)
		{
			printf("width == 0 || height == 0");
			return;
		}
		dst = org(Rect(min(cur_pt.x, pre_pt.x), min(cur_pt.y, pre_pt.y), width, height));
		//cv::resize(dst, dst, savesize);
		cv::imwrite(savefolder + "\\img_" + to_string(cnt) + ".jpg", dst);
		cnt++;
		imshow("dst", dst);
		waitKey(0);
	}
}
![](/img/opencv_mouse.png)
```

